#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,m,s[N],f[N][21],c[N],dep[N];
long long ans;
vector<int> g[2][N];

void dfs1(int x,int fa){
	int len=g[0][x].size();
	dep[x]=dep[fa]+1;
	for(int i=0;i<len;i++)
		if(g[0][x][i]!=fa){
			int v=g[0][x][i];
			f[v][0]=x;
			for(int j=1;f[f[v][j-1]][j-1];j++)
				f[v][j]=f[f[v][j-1]][j-1];
			dfs1(v,x);
		}
}

int LCA(int x,int y){
	if(dep[x]<dep[y])
		swap(x,y);
	for(int i=20;i>=0;i--)
		if(dep[f[x][i]]>=dep[y])
			x=f[x][i];
	if(x==y)
		return x;
	for(int i=20;i>=0;i--)
		if(f[x][i]!=f[y][i])
			x=f[x][i],y=f[y][i];
	return f[x][0];
}

void dfs2(int x,int fa){
	int len=g[0][x].size();
	for(int i=0;i<len;i++)
		if(g[0][x][i]!=fa){
			dfs2(g[0][x][i],x);
			c[x]+=c[g[0][x][i]]; 
		}
	len=g[1][x].size();
	for(int i=0;i<len;i++)
		if(LCA(g[1][x][i],x)!=x)
			c[x]++,c[LCA(g[1][x][i],x)]--;
	if(!c[x] && x!=1)
		ans+=m;
	else if(c[x]==1 && x!=1)
		ans++;
	//printf("%d %d\n",x,c[x]); 
}

int main(){
	scanf("%d%d",&n,&m);
	for(int i=1,u,v;i<n;i++){
		scanf("%d%d",&u,&v);
		g[0][u].push_back(v);
		g[0][v].push_back(u);
	}
	for(int i=1,u,v;i<=m;i++){
		scanf("%d%d",&u,&v);
		g[1][u].push_back(v);
		g[1][v].push_back(u);
	}
	dfs1(1,0);
	dfs2(1,0);
	printf("%lld",ans);
	return 0;
}
